INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '71a06049-3d1a-43f9-a0a7-a86dc95c3fac',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Component Variants — Managing Sizes, States & Themes with CVA$escape$,
  $escape$Hardcoding variant logic as template literals breaks fast. `class-variance-authority` (CVA) solves this by treating Tailwind classes as typed, composable slots. You define a base, declare variant keys, and let CVA merge everything at call time — no manual string juggling, no accidental class conflicts.

CVA pairs naturally with `tailwind-merge` (via `clsx`) to resolve Tailwind's specificity issues when callers override defaults. For example, a Button with `size: 'sm'` and `intent: 'danger'` resolves to a single, conflict-free class string.

`tailwind-variants` is a newer alternative that ships merge behaviour built-in and adds `slots` — letting you style multi-element components (trigger + content + icon) from one variant definition, keeping compound components coherent.

Both tools are fully compatible with Tailwind's JIT scanner: keep class names string-literal-complete inside the config object and your purge step will never strip active classes. Avoid constructing class fragments dynamically (e.g. `\`text-${color}-500\``) — write the full class name instead.$escape$,
  $escape$import { cva, type VariantProps } from 'class-variance-authority';
import { twMerge } from 'tailwind-merge';
import { clsx } from 'clsx';

const button = cva(
  'inline-flex items-center font-medium rounded-md transition-colors focus-visible:outline-none focus-visible:ring-2',
  {
    variants: {
      intent: {
        primary: 'bg-blue-600 text-white hover:bg-blue-700 focus-visible:ring-blue-500',
        danger:  'bg-red-600  text-white hover:bg-red-700  focus-visible:ring-red-500',
        ghost:   'bg-transparent text-slate-700 hover:bg-slate-100',
      },
      size: {
        sm: 'px-3 py-1.5 text-sm',
        md: 'px-4 py-2   text-base',
        lg: 'px-6 py-3   text-lg',
      },
    },
    defaultVariants: { intent: 'primary', size: 'md' },
  }
);

type ButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & VariantProps<typeof button>;

export function Button({ intent, size, className, ...props }: ButtonProps) {
  return <button className={twMerge(clsx(button({ intent, size }), className))} {...props} />;
}$escape$,
  $escape$typescript$escape$,
