INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1846ff60-c0f2-4651-b1bc-56aa4a477e89',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Responsive Design — Mobile-First Breakpoints, Container Queries, and Fluid Typography$escape$,
  $escape$Tailwind's breakpoint system is mobile-first by default — unprefixed utilities apply at all sizes, and prefixed ones (`sm:`, `md:`, `lg:`, `xl:`, `2xl:`) activate at that width and above. Never write `sm:text-base md:text-base` — just `text-base`. For layout shifts, prefer stacking modifiers: `flex-col md:flex-row`.

Container queries (`@container`) let you style based on a parent's size, not the viewport. Add `@container` to the parent, then use `@sm:`, `@md:` on children. This is a game-changer for reusable card components that live inside sidebars or full-width layouts simultaneously — the card responds to its slot, not the screen.

For fluid typography, Tailwind v4 introduces first-class support via `text-[clamp(1rem,2.5vw,1.5rem)]` using arbitrary values, or configure `fontSize` in `tailwind.config` with `clamp()` values. Pair with `fluid-cols` grid patterns using `grid-cols-[repeat(auto-fill,minmax(min(100%,20rem),1fr))]` for truly viewport-agnostic layouts without a single media query breakpoint.$escape$,
  $escape$<div class="@container">
  <div class="
    flex flex-col gap-4
    @md:flex-row @md:items-center
    p-4 rounded-xl bg-white shadow
  ">
    <img class="w-full @md:w-24 @md:h-24 rounded-lg object-cover" src="/thumb.jpg" />
    <div>
      <h2 class="text-base @md:text-lg font-semibold">
        Container-aware Card
      </h2>
      <p class="text-sm text-slate-500 mt-1">
        Responds to parent width, not viewport.
      </p>
    </div>
  </div>
</div>$escape$,
  $escape$javascript$escape$,
