INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3582c754-6ee9-4d92-9f92-b0681c124014',
  '00000000-0000-0000-0000-000000000001',
  $escape$tailwindcss Typography — Type Scale, Font Loading, and font-display swap$escape$,
  $escape$Tailwind's default type scale (text-xs through text-9xl) maps to a harmonious modular ratio, but font loading strategy determines whether users see that scale or a flash of invisible text. Configure custom fonts in tailwind.config.js under theme.extend.fontFamily, then pair them with a @font-face rule that sets font-display: swap — this ensures fallback fonts render immediately while the custom font loads, eliminating layout shifts on slow connections.

In Tailwind v4's CSS-first config, declare @theme { --font-sans: 'Inter', sans-serif; } directly in your CSS, then reference it with font-sans. Preload critical fonts via <link rel="preload" as="font"> in your HTML head to shave 200–400ms off first paint. For variable fonts, use font-variation-settings through Tailwind's arbitrary value syntax: [font-variation-settings:'wght'_700]. Combine text-balance on headings and text-pretty on body copy (both Tailwind utilities wrapping the CSS text-wrap property) to prevent widows without JavaScript. Avoid loading multiple font weights — one variable font file beats four static weights every time.$escape$,
  $escape$/* globals.css — Tailwind v4 CSS-first config */
@import "tailwindcss";

@font-face {
  font-family: 'Inter';
  src: url('/fonts/Inter.var.woff2') format('woff2');
  font-weight: 100 900;
  font-display: swap;
}

@theme {
  --font-sans: 'Inter', ui-sans-serif, system-ui;
}

/* Usage in JSX */
// <h1 className="font-sans text-4xl font-bold tracking-tight text-balance">
// <p className="font-sans text-base font-normal leading-relaxed text-pretty">$escape$,
  $escape$bash$escape$,
