INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'adfbeb11-3966-4eac-ab97-8a1d794483e8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS — How Utility-First Ends Specificity Wars for Good$escape$,
  $escape$Traditional CSS specificity wars stem from compound selectors: `.card .title` carries (0,2,0) and beats `.highlight` (0,1,0) regardless of source order. Tailwind sidesteps this entirely — every utility is a single-class selector with identical specificity (0,1,0). Conflicts resolve purely by CSS source order in Tailwind's generated stylesheet, which is deterministic and controlled by Tailwind's internal ordering, not your class list order in JSX.

This is the most common footgun: `className="text-red-500 text-blue-500"` doesn't behave intuitively — `text-blue-500` wins because it appears later in the generated CSS, not because it's last in your string. When you genuinely need a guaranteed override, use the `!` modifier: `!text-blue-500` compiles to `color: ... !important`.

For custom utilities, always wrap them in `@layer utilities` in your CSS entry point. This slots them into the same specificity layer as Tailwind's own classes, preserving the flat cascade. Adding styles outside this layer reintroduces the specificity coupling Tailwind was designed to eliminate. Avoid `@apply` for overrides for the same reason — it extracts utilities from their layer and creates hidden coupling.$escape$,
  $escape$// ❌ Class list order does NOT determine the winner — Tailwind's generated order does
<p className="text-red-500 text-blue-500">Blue wins (later in generated CSS)</p>

// ✅ ! modifier forces !important — guaranteed override
<p className="text-red-500 !text-blue-500">Blue wins (explicit)</p>

// ✅ Custom utilities inside @layer — stays flat, no specificity leak
// app/globals.css
// @layer utilities {
//   .text-brand { color: #6366f1; }
// }
<p className="text-brand text-red-500">Brand wins (source order, predictable)</p>

// ❌ @apply outside @layer — escapes the contract, reintroduces cascade bugs
// .card-title { @apply text-xl font-bold; } → now lives outside utilities layer$escape$,
  $escape$typescript$escape$,
