INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9111d9a7-2382-4c1a-9b7d-d42e166b766a',
  '00000000-0000-0000-0000-000000000001',
  $escape$tailwindcss CSS Custom Properties — Runtime Theming, JS Interop, and Component Scoping$escape$,
  $escape$Tailwind v4 ships your entire design system as CSS custom properties — `--color-sky-500`, `--spacing-4`, `--font-sans` live on `:root` by default via `@theme`. This makes runtime theming a first-class pattern, not a workaround.

To scope tokens to a component, set a CSS variable via the inline `style` prop and consume it with Tailwind's arbitrary-value syntax: `bg-[--my-var]`. Tailwind emits a valid `var()` reference at build time, so you get full utility support — including opacity modifiers like `bg-[--my-var]/50` and JIT-resolved shadows.

For JavaScript interop, `element.style.setProperty('--color-brand', value)` updates a token without touching class lists. Paired with `@theme inline` in your CSS entry point, every Tailwind token becomes a live override target — swap dark mode palettes, user accent colors, or per-tenant branding by writing one property.

Avoid `@apply` for dynamic tokens; it resolves at build time and cannot reflect runtime values. Use `className` for static utilities and the `style` prop exclusively for live custom properties.$escape$,
  $escape$// Tailwind v4: inject a runtime token via style prop, consume it as a utility
function ThemedCard({ hue }: { hue: number }) {
  return (
    <div
      style={{ '--color-accent': `oklch(0.65 0.2 ${hue})` } as React.CSSProperties}
      className="rounded-xl p-6 bg-[--color-accent] shadow-[0_4px_24px_--color-accent]/40"
    >
      <p className="text-white/80">Scoped token — no CSS-in-JS needed</p>
      <button
        onClick={() =>
          document.documentElement.style.setProperty('--color-accent', `oklch(0.65 0.2 ${hue + 60})`)
        }
        className="mt-4 px-3 py-1 rounded bg-[--color-accent]/20 text-white text-sm"
      >
        Shift hue globally
      </button>
    </div>
  );
}$escape$,
  $escape$typescript$escape$,
