INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5dded368-f5c9-4123-88b8-82211f1a682b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Global Styles — Resets, Base Typography, and Keeping Components Clean$escape$,
  $escape$Tailwind's Preflight (built on modern-normalize) resets all browser defaults automatically when you import Tailwind — margins zeroed, headings unstyled, buttons borderless. This is injected into the `@layer base` layer. You extend it in the same layer inside your CSS entry point, never inside component files. Add base typography there: `@apply text-base text-neutral-900 leading-normal font-sans` on `body`. For fluid type scales, wire CSS custom properties in `@layer base` and reference them via `theme()` or arbitrary values. The critical discipline: `@layer base` rules are global and have zero specificity advantage — any component-level utility overrides them cleanly. This means leakage is a non-issue if you stay in utilities inside components. Leakage happens when you write naked element selectors (`h2 { ... }`) outside `@layer base`, which bleed through the cascade unpredictably. Keep all global element styling inside `@layer base`, all design tokens inside `@theme` (v4) or `tailwind.config.js` `theme.extend`, and never reach for a global selector inside a component stylesheet.$escape$,
  $escape$/* globals.css */
@import 'tailwindcss';

@layer base {
  body {
    @apply text-base leading-relaxed text-neutral-900 font-sans antialiased;
  }

  h1, h2, h3, h4 {
    @apply font-semibold tracking-tight text-neutral-950;
  }

  a {
    @apply text-blue-600 underline underline-offset-2 hover:text-blue-800;
  }
}

/* ✅ Component: override freely, no cascade fights */
/* <p className="text-sm text-gray-500 no-underline"> */$escape$,
