INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2e593041-af82-4aad-8618-b80505cb61c7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Scoping — Containing Style Bleed with CSS Modules, important, and prefix$escape$,
  $escape$Tailwind utilities are global — every class lands in one compiled stylesheet. That's fine until you embed a widget, share a DOM with a legacy stylesheet, or run multiple Tailwind instances in a micro-frontend shell.

Three scoping levers exist:

**CSS Modules + `@apply`**: Write `@apply` directives inside a `.module.css` file. The bundler hashes the class names, giving component-level isolation while still consuming your Tailwind design tokens. Variants (`hover:`, `dark:`, `focus-visible:`) and arbitrary values all resolve correctly inside `@apply`.

**`important` string strategy**: Set `important: '#app'` in `tailwind.config.ts`. Every utility gets an `#app`-prefixed selector (`#app .flex`), lifting specificity above third-party base styles without scattering `!` modifiers across markup.

**`prefix` option**: Set `prefix: 'tw-'` to namespace every generated class (`tw-flex`, `tw-text-sm`). Mandatory when two Tailwind bundles coexist in the same document — otherwise identical class names from different configs silently override each other.

Avoid `@layer components` for component-scoped styles — it's intentionally global and leaks across your whole app. Reserve it for app-wide primitives; push component-specific composition into CSS Modules.$escape$,
  $escape$// tailwind.config.ts — scope utilities under #app, prefix to avoid collisions
export default {
  content: ['./src/**/*.{ts,tsx}'],
  important: '#app',  // → #app .tw-rounded-xl { border-radius: 0.75rem }
  prefix: 'tw-',
} satisfies import('tailwindcss').Config

// Card.module.css — hashed classnames, Tailwind tokens via @apply
// .card  { @apply tw-rounded-xl tw-border tw-border-neutral-200 tw-p-6 tw-shadow-sm; }
// .title { @apply tw-text-lg tw-font-semibold tw-text-neutral-900; }

// Card.tsx
import styles from './Card.module.css'
export function Card({ title }: { title: string }) {
  return <div className={styles.card}><h2 className={styles.title}>{title}</h2></div>
}$escape$,
  $escape$typescript$escape$,
