INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '18264d67-113b-4ffb-80d3-89b17652ecf2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Accessibility — focus-visible, Contrast, and Never Color Alone$escape$,
  $escape$Tailwind's `focus:` variant fires on any focus, including mouse clicks — this creates noisy outlines that designers remove globally, gutting keyboard nav. Use `focus-visible:` instead: it mirrors the browser's native `:focus-visible` behavior, showing rings only for keyboard users. Pair `focus-visible:outline-none` with `focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-indigo-500` to suppress the default outline while providing a clear, styled ring.

For color contrast, Tailwind's palette bakes in WCAG-safe combinations at specific shade pairings — `text-gray-900` on `bg-white` clears AA at ~16:1, but `text-gray-400` on `bg-white` fails at ~3:1. Always verify with the `bg-*/text-*` pair, not individual tokens.

Never use color as the sole differentiator. An error state using only `text-red-500` fails for colorblind users. Combine with `ring-red-500`, an icon (`aria-hidden`), and `aria-invalid="true"` on the input. Tailwind's `aria-invalid:ring-red-500` variant (v3.2+) lets you drive this purely from the DOM attribute, keeping your logic in HTML rather than scattered class conditions.$escape$,
  $escape$<input
  type="email"
  aria-invalid={hasError}
  className="
    rounded-md border px-3 py-2
    border-gray-300
    focus:outline-none
    focus-visible:ring-2
    focus-visible:ring-offset-2
    focus-visible:ring-indigo-500
    aria-[invalid=true]:border-red-500
    aria-[invalid=true]:ring-red-500
    aria-[invalid=true]:ring-1
  "
/>$escape$,
  $escape$javascript$escape$,
