INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cc86e9f5-5050-41c0-87bd-10077287f5cc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Bundle Optimization — Purging, Font Subsetting, and Icon Strategy$escape$,
  $escape$Tailwind's JIT engine in v3+ scans your content globs and emits only used utilities — but misconfigured `content` paths silently bloat production bundles. Ensure `tailwind.config.ts` covers every file that interpolates class names, including dynamic ones via `safelist` with regex patterns for programmatic variants like `bg-${color}-500`.

For fonts, avoid loading full variable font files. Use `font-display: swap` via the `@font-face` block in your CSS layer and subset with `glyphs` ranges — or lean on `next/font` which auto-subsets and scopes the CSS custom property to the layout, preventing FOUT without a global stylesheet penalty.

For icons, never import an entire icon library. With Heroicons or Lucide, use named ESM imports so tree-shaking eliminates unused SVGs. Alternatively, inline critical icons as Tailwind `bg-` mask utilities using `mask-image` with a data URI — zero extra HTTP requests, fully utility-driven sizing via `w-` and `h-` classes, and no runtime JS.$escape$,
  $escape$// tailwind.config.ts
import type { Config } from 'tailwindcss'

export default {
  content: [
    './app/**/*.{ts,tsx}',
    './components/**/*.{ts,tsx}',
  ],
  safelist: [
    { pattern: /^bg-(red|blue|green)-(400|500|600)$/ },
  ],
  theme: {
    extend: {
      // Inline icon as mask utility
      backgroundImage: {
        'icon-check': "url(\"data:image/svg+xml,...\")",
      },
    },
  },
} satisfies Config$escape$,
  $escape$typescript$escape$,
