INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1a9a22d-14b1-436f-9fcb-9c68175c59e1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Visual Regression — Why Chromatic Beats Snapshot Tests$escape$,
  $escape$Snapshot testing Tailwind components is a trap. Your Jest snapshots capture class strings like `className="flex items-center gap-4 rounded-lg bg-blue-500 p-3 text-white hover:bg-blue-600"` — but a snapshot diff fires when you reorder utilities or add `dark:` variants, even when the rendered output is pixel-identical. Tailwind's JIT engine and Prettier's class sorting (via `prettier-plugin-tailwindcss`) will routinely mutate class order, turning every refactor into a sea of false-positive diffs.

Chromatic (or Percy) solves this by diffing rendered pixels, not strings. Pair it with Storybook: write stories that exercise your Tailwind variants — hover states via `data-*` attributes, dark mode via `.dark` on a parent, responsive breakpoints via viewport presets. Chromatic snapshots each story at defined viewports and flags only genuine visual regressions. One gotcha: ensure your Storybook build imports your compiled `globals.css` (the file with `@tailwind base/components/utilities`), not a stub — otherwise JIT-purged classes silently vanish from snapshots and you get false negatives instead of false positives.$escape$,
  $escape$// .storybook/preview.ts
import '../src/app/globals.css'; // must include @tailwind directives
import type { Preview } from '@storybook/react';

const preview: Preview = {
  parameters: {
    chromatic: {
      // Capture at Tailwind's default breakpoints
      viewports: [375, 768, 1280],
      // Force dark-mode story variant
      modes: {
        dark: { backgrounds: { value: '#0f172a' } },
      },
    },
  },
  decorators: [
    (Story, ctx) => (
      <div className={ctx.globals.theme === 'dark' ? 'dark' : ''}>
        <Story />
      </div>
    ),
  ],
};

export default preview;$escape$,
