INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9cd5fc58-7320-43da-9192-33991e078627',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tailwind CSS Design System Integration — Wiring Tokens, Components, and the Config Layer$escape$,
  $escape$Tailwind's `tailwind.config.ts` is your single source of truth for design tokens. Define semantic tokens under `theme.extend` — colors, spacing, radii — and every component inherits them automatically without a separate token file. Use CSS custom properties (via `@layer base`) to bridge Tailwind and a headless library like Radix or shadcn/ui: set `--radius`, `--background`, etc. in `:root`, then map them in config with `hsl(var(--background))`. This means your component library reads the same tokens Tailwind utilities expose, keeping both in sync.

For a scalable component API, use `cva` (class-variance-authority) to encode variant logic against your design tokens. Each variant maps to a Tailwind class grounded in `theme` values — not arbitrary hex codes. When a token changes in config, every component variant updates. Pair this with `tailwind-merge` to safely compose utility classes without specificity collisions. The result: a fully typed, token-driven component system where the styling layer, component library, and design tokens are a single coherent graph — not three separate concerns duct-taped together.$escape$,
  $escape$// tailwind.config.ts
import type { Config } from 'tailwindcss'

export default {
  theme: {
    extend: {
      colors: {
        background: 'hsl(var(--background))',
        primary: 'hsl(var(--primary))',
        'primary-foreground': 'hsl(var(--primary-foreground))',
      },
      borderRadius: {
        DEFAULT: 'var(--radius)',
      },
    },
  },
} satisfies Config

// globals.css
@layer base {
  :root {
    --background: 0 0% 100%;
    --primary: 221 83% 53%;
    --primary-foreground: 210 40% 98%;
    --radius: 0.5rem;
  }
}

// button.tsx — cva variant consuming the tokens
import { cva } from 'class-variance-authority'

export const button = cva(
  'inline-flex items-center rounded transition-colors',
  {
    variants: {
      intent: {
        primary: 'bg-primary text-primary-foreground hover:bg-primary/90',
        ghost: 'bg-transparent hover:bg-primary/10 text-primary',
      },
    },
    defaultVariants: { intent: 'primary' },
  }
)$escape$,
  $escape$typescript$escape$,
